INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 102301, 10046, "アヤネ", 2, 401, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 2, 0.0, 24001);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 102301, 10046, "アヤネ", 2, 402, "2020/07/31 12:00:00", 2.21, 24, "2030/12/17 14:59:59", 1, 0.0, 24002);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 102301, 10046, "アヤネ", 2, 403, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 2, 0.0, 24003);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 192201, 10046, "アサヒ", 1, 701, "2020/07/31 12:00:00", 1.99, 24, "2030/12/17 14:59:59", 2, 0.0, 24004);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 192201, 10046, "アサヒ", 2, 702, "2020/07/31 12:00:00", 2.21, 24, "2030/12/17 14:59:59", 1, 0.0, 24005);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 192201, 10046, "アサヒ", 1, 703, "2020/07/31 12:00:00", 3.33, 24, "2030/12/17 14:59:59", 2, 0.0, 24006);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 192301, 10046, "部員３", 2, 801, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 2, 0.0, 24007);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 192301, 10046, "部員３", 2, 802, "2020/07/31 12:00:00", 2.68, 24, "2030/12/17 14:59:59", 1, 0.0, 24008);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 192301, 10046, "部員３", 2, 803, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 2, 0.0, 24009);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "やった！", 192501, 10046, "", 1, 501, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 1, 0.0, 24010);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "勝ったよ！", 192501, 10046, "", 1, 502, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 1, 0.0, 24011);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "いい調子！", 192501, 10046, "", 1, 503, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 1, 0.0, 24012);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 113501, 10046, "ミサト", 2, 111, "2020/07/31 12:00:00", 5.33, 24, "2030/12/17 14:59:59", 6, 0.0, 24013);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 113501, 10046, "ミサト", 2, 112, "2020/07/31 12:00:00", 6.85, 24, "2030/12/17 14:59:59", 1, 0.0, 24014);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113501, 10046, "ミサト", 2, 113, "2020/07/31 12:00:00", 3.0, 24, "2030/12/17 14:59:59", 1, 0.0, 24015);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 192401, 10046, "ダイチ", 2, 611, "2020/07/31 12:00:00", 6.11, 24, "2030/12/17 14:59:59", 1, 0.0, 24016);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 192401, 10046, "ダイチ", 2, 612, "2020/07/31 12:00:00", 6.75, 24, "2030/12/17 14:59:59", 1, 0.0, 24017);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 192401, 10046, "ダイチ", 2, 613, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 2, 0.0, 24018);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 113401, 10046, "ハツネ", 1, 211, "2020/07/31 12:00:00", 4.52, 24, "2030/12/17 14:59:59", 2, 0.0, 24019);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 113401, 10046, "ハツネ", 1, 212, "2020/07/31 12:00:00", 3.89, 24, "2030/12/17 14:59:59", 2, 0.0, 24020);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 113401, 10046, "ハツネ", 2, 213, "2020/07/31 12:00:00", 13.49, 24, "2030/12/17 14:59:59", 1, 0.0, 24021);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 106501, 10046, "カヤ", 2, 311, "2020/07/31 12:00:00", 3.17, 24, "2030/12/17 14:59:59", 1, 0.0, 24022);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 106501, 10046, "カヤ", 2, 312, "2020/07/31 12:00:00", 4.42, 24, "2030/12/17 14:59:59", 1, 0.0, 24023);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 106501, 10046, "カヤ", 1, 313, "2020/07/31 12:00:00", 2.89, 24, "2030/12/17 14:59:59", 6, 0.0, 24024);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 102301, 10046, "アヤネ", 3, 421, "2020/07/31 12:00:00", 3.71, 24, "2030/12/17 14:59:59", 4, 0.0, 24025);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 192201, 10046, "アサヒ", 1, 721, "2020/07/31 12:00:00", 5.1, 24, "2030/12/17 14:59:59", 2, 0.0, 24026);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 192301, 10046, "部員３", 3, 821, "2020/07/31 12:00:00", 4.34, 24, "2030/12/17 14:59:59", 1, 0.0, 24027);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "いい勝負だったよ\nまたやろうね", 192501, 10046, "", 1, 521, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 1, 0.0, 24028);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 113501, 10046, "ミサト", 2, 101, "2020/07/31 12:00:00", 5.62, 24, "2030/12/17 14:59:59", 1, -360.0, 24029);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 113501, 10046, "ミサト", 2, 102, "2020/07/31 12:00:00", 9.58, 24, "2030/12/17 14:59:59", 1, -360.0, 24030);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 113501, 10046, "ミサト", 2, 103, "2020/07/31 12:00:00", 0.0, 24, "2030/12/17 14:59:59", 2, -360.0, 24031);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 113501, 10046, "ミサト", 1, 104, "2020/07/31 12:00:00", 9.13, 24, "2030/12/17 14:59:59", 2, -360.0, 24032);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES (0.0, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 113501, 10046, "ミサト", 2, 105, "2020/07/31 12:00:00", 8.27, 24, "2030/12/17 14:59:59", 1, -360.0, 24033);
